+            let mut ranked: Vec<_> = group_slices.iter()
+                .map(|s| (*s, s.utility_score / s.token_estimate as f32))
+                .collect();
+            ranked.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
